/**
 * runCompletionManifestRegen helper tests (mt#2622).
 *
 * `src/generated/completion-manifest.json` was regenerated by
 * `scripts/build-completion-manifest.ts` on any CLI-tree change but never
 * atomically with the commit that invalidated it — 13 dedicated "sync
 * manifest" commits landed in a 300-commit window, and a 4,227-line dirty
 * diff was sitting unstaged at audit time (mt#2607 finding 7/9). The
 * pre-commit `runCompletionManifestRegen` step now regenerates the manifest
 * on every commit and re-stages it if it changed. These tests pin the two
 * pure decision helpers that step depends on: whether the regenerated file
 * actually differs from the index, and how a generator failure is reported.
 */
import { describe, test, expect } from "bun:test";
import { manifestDiffIndicatesChange, classifyCompletionManifestRegenError } from "./pre-commit";

describe("manifestDiffIndicatesChange (mt#2622)", () => {
  test("empty diff stdout → no change", () => {
    expect(manifestDiffIndicatesChange("")).toBe(false);
  });

  test("whitespace-only diff stdout → no change", () => {
    expect(manifestDiffIndicatesChange("\n")).toBe(false);
    expect(manifestDiffIndicatesChange("   \n  ")).toBe(false);
  });

  test("diff stdout naming the manifest path → changed", () => {
    expect(manifestDiffIndicatesChange("src/generated/completion-manifest.json\n")).toBe(true);
  });
});

describe("classifyCompletionManifestRegenError (mt#2622)", () => {
  test("prefers stderr over stdout when both are present", () => {
    const result = classifyCompletionManifestRegenError({
      stdout: "some stdout noise",
      stderr: "TypeError: cannot read property 'options' of undefined",
    });
    expect(result.message).toBe(
      "Completion-manifest regeneration failed: TypeError: cannot read property 'options' of undefined"
    );
    expect(result.logLines[0]).toBe("❌ Completion-manifest regeneration failed:");
    expect(result.logLines).toContain("   TypeError: cannot read property 'options' of undefined");
  });

  test("falls back to stdout when stderr is empty", () => {
    const result = classifyCompletionManifestRegenError({
      stdout: "Error: something went wrong\n  at main (scripts/build-completion-manifest.ts:212:9)",
      stderr: "",
    });
    expect(result.message).toBe(
      "Completion-manifest regeneration failed: Error: something went wrong"
    );
    // Both lines of the multi-line detail are indented and preserved.
    expect(result.logLines).toContain("   Error: something went wrong");
    expect(result.logLines).toContain("     at main (scripts/build-completion-manifest.ts:212:9)");
  });

  test("falls back to Error.message when neither stdout nor stderr is present", () => {
    const result = classifyCompletionManifestRegenError(new Error("spawn ENOENT"));
    expect(result.message).toBe("Completion-manifest regeneration failed: spawn ENOENT");
  });

  test("falls back to String(error) for a non-Error, non-exec-result throw", () => {
    const result = classifyCompletionManifestRegenError("timeout");
    expect(result.message).toBe("Completion-manifest regeneration failed: timeout");
  });

  test("always includes the actionable hint that re-running will not help", () => {
    const result = classifyCompletionManifestRegenError(new Error("boom"));
    expect(result.logLines.at(-1)).toContain("re-running the commit will NOT help");
  });
});
